"""
🔄 Hedge-Cycle State Machine v2
Works in BOTH one-way and hedge mode.
One-way: sequential (LONG → flat → SHORT → flat)
Hedge: simultaneous (LONG+SHORT together)
"""
import time
from enum import Enum

class State(Enum):
    IDLE = 'IDLE'
    FLAT = 'FLAT'
    HEDGING = 'HEDGING'       # Both sides open (hedge mode)
    SCALPING = 'SCALPING'     # One side open (one-way mode)
    RELEASING = 'RELEASING'
    TRAILING = 'TRAILING'
    COOLDOWN = 'COOLDOWN'
    STOPPED = 'STOPPED'


class HedgeCycleMachine:
    """
    Adapts between hedge and one-way mode.
    Hedge mode: open LONG+SHORT → release loser → trail winner
    One-way mode: decide direction → enter → trail → exit → flip
    """
    def __init__(self, exchange, risk, pmcs_filter, release_logic, trail_mgr):
        self.ex = exchange
        self.risk = risk
        self.pmcs = pmcs_filter
        self.release = release_logic
        self.trail = trail_mgr

        self.state = State.IDLE
        self.symbol = None
        self.long_pos = None
        self.short_pos = None
        self.hedge_open_time = 0
        self.algo_ids = []
        self.cycle_log = []
        self.last_direction = None  # Track which direction we last traded

    def log(self, msg, level='INFO'):
        ts = time.strftime('%H:%M:%S')
        icons = {
            'INFO': '📊', 'ENTRY': '🚀', 'RELEASE': '🔄',
            'TRAIL': '📈', 'EXIT': '💰', 'WARN': '⚠️',
            'ERROR': '❌', 'COOLDOWN': '😴', 'STATE': '🔵'
        }
        icon = icons.get(level, '📊')
        line = f"[{ts}] {icon} [{self.state.value}] {msg}"
        print(line, flush=True)
        self.cycle_log.append(line)

    @property
    def is_hedge_mode(self):
        return self.ex._hedge_mode

    # ─── Main tick ───
    def tick(self):
        if self.state == State.IDLE:
            return self._do_idle()
        elif self.state == State.FLAT:
            return self._do_flat()
        elif self.state == State.HEDGING:
            return self._do_hedging()
        elif self.state == State.SCALPING:
            return self._do_scalping()
        elif self.state == State.RELEASING:
            return self._do_releasing()
        elif self.state == State.TRAILING:
            return self._do_trailing()
        elif self.state == State.COOLDOWN:
            return self._do_cooldown()
        elif self.state == State.STOPPED:
            return False
        return True

    def _do_idle(self):
        self.log(f"Mode: {'HEDGE' if self.is_hedge_mode else 'ONE-WAY'}", 'STATE')

